// Prebuild script that computes the SHA256 of `resources/install.ps1`
// and writes it to `src/main/generated/installPs1Hash.ts` as a TypeScript
// constant. The generated file is compiled into `app.asar` via
// electron-vite and read at runtime by `WindowsInstallerStrategy.install()`
// to verify the vendored script hasn't been tampered with between builds.
//
// This runs BEFORE `electron-vite build` via the `prebuild` npm script.
// The generated file is committed to git (not gitignored) so that hash
// bumps appear as reviewable diffs in PRs — an attacker who wants to
// swap `install.ps1` must also land a PR that updates this constant,
// and code review can spot the hash-only diff.
//
// Why both this AND the afterPack sidecar? Defense in depth:
// - afterPack writes a JSON sidecar next to the packaged install.ps1 for
//   external audit tooling. Not read by the app.
// - This prebuild script generates a TypeScript constant embedded in
//   app.asar. Read by the app at runtime before spawning PowerShell.
//   Tampering it requires repacking the asar, which Electron's asar
//   integrity fuse detects (when enabled).
//
// See docs/M1_1_TICKETS.md M1.1-#005 for the full rationale.

// eslint-disable-next-line @typescript-eslint/no-require-imports
const { createHash } = require("crypto");
// eslint-disable-next-line @typescript-eslint/no-require-imports
const { readFileSync, writeFileSync, mkdirSync, existsSync } = require("fs");
// eslint-disable-next-line @typescript-eslint/no-require-imports
const path = require("path");

const REPO_ROOT = path.resolve(__dirname, "..");
const SRC = path.join(REPO_ROOT, "resources", "install.ps1");
const OUT_DIR = path.join(REPO_ROOT, "src", "main", "generated");
const OUT = path.join(OUT_DIR, "installPs1Hash.ts");

if (!existsSync(SRC)) {
  console.error(
    `[generateInstallPs1Hash] resources/install.ps1 not found at ${SRC}`,
  );
  process.exit(1);
}

const hash = createHash("sha256").update(readFileSync(SRC)).digest("hex");

mkdirSync(OUT_DIR, { recursive: true });

const contents =
  `// AUTO-GENERATED — do not edit.\n` +
  `// Regenerated by \`build/generateInstallPs1Hash.js\` on every build.\n` +
  `// Updates to this file must correspond to an intentional update of\n` +
  `// \`resources/install.ps1\` (e.g. vendoring a new upstream commit).\n` +
  `//\n` +
  `// See docs/M1_1_TICKETS.md M1.1-#005 for the runtime integrity check\n` +
  `// that consumes this constant.\n` +
  `\n` +
  `export const INSTALL_PS1_SHA256 = ${JSON.stringify(hash)} as const;\n`;

writeFileSync(OUT, contents, "utf8");
console.log(`[generateInstallPs1Hash] wrote ${OUT}`);
console.log(`[generateInstallPs1Hash] install.ps1 sha256 = ${hash}`);
